//
// Generates the reference documentation pages for /docs/next from authoritative source:
//   - emitter output (providers.json, contract-sets.json, bootstrap-config.json) produced by
//     the agentforge4j-docs-emitter Maven tool (reflection over the installed OSS artifacts),
//   - the Spring configuration metadata JSON (build-generated by the configuration processor),
//   - the curated env/system-property key fixture (env-sysprop-keys.json),
//   - the five JSON schemas in agentforge4j-schema.
//
// No page is hand-authored; this script only transforms JSON into MDX. It never parses Java source.
// Generated output is gitignored and regenerated at build time, so it cannot drift from source.
// Run AFTER the emitter (see scripts/README or the module README for the full sequence).

import {existsSync, mkdirSync, readFileSync, writeFileSync} from 'node:fs';
import {dirname, join} from 'node:path';
import {fileURLToPath} from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const MODULE_ROOT = join(here, '..');
const REPO_ROOT = join(MODULE_ROOT, '..');
const EMITTER_OUT = join(here, 'emitter-output');
const REFERENCE_DIR = join(MODULE_ROOT, 'docs', 'reference');
const SCHEMA_DIR = join(REPO_ROOT, 'agentforge4j-schema', 'src', 'main', 'resources', 'schema');
const SPRING_METADATA = join(
  REPO_ROOT,
  'agentforge4j-spring-boot-starter',
  'target',
  'classes',
  'META-INF',
  'spring-configuration-metadata.json',
);

/** Read a required JSON input; fail fast (the build must not silently emit partial references). */
function readJson(path, what) {
  if (!existsSync(path)) {
    console.error(`generate-references: missing ${what}: ${path}`);
    console.error('Run the OSS reactor build and the docs emitter first (see the module README).');
    process.exit(1);
  }
  return JSON.parse(readFileSync(path, 'utf8'));
}

/**
 * Reduce a Javadoc `{@link[plain] fqcn[#member]}` reference to a short, readable name: the
 * simple type name (last dot-separated segment), plus `#member` if the reference points at a
 * member rather than the type itself.
 */
export function shortJavadocRef(ref) {
  const [type, member] = ref.split('#');
  const shortType = type.trim().split('.').pop();
  return member ? `${shortType}#${member.trim()}` : shortType;
}

/**
 * Source Javadoc comments routinely contain `{@code x}`/`{@link x}`/`{@linkplain x}` block tags.
 * Reflected/emitted descriptions carry that markup verbatim, so normalize it to plain readable
 * text here, once, at the generator boundary — never by hand-editing generated output.
 * `{@code x}` becomes inline code; `{@link[plain] x}` becomes the short type name as inline code
 * (this generator has no Javadoc-surface path-resolution context to build a real hyperlink, unlike
 * the docs' own `javadoc:<fqcn>` remark role, which prose authors should use directly instead).
 */
export function normalizeJavadocTags(text) {
  return text
    .replace(/\{@code\s+([^}]+)\}/g, (_, body) => `\`${body.trim()}\``)
    .replace(/\{@link(?:plain)?\s+([^}]+)\}/g, (_, body) => `\`${shortJavadocRef(body.trim())}\``);
}

/**
 * Escape a cell value for a Markdown table inside MDX. Besides the table pipe and newlines, MDX
 * treats `{` as a JS expression and `<` as a JSX tag, so any left after Javadoc-tag normalization
 * (and angle brackets) are HTML-escaped.
 */
export function cell(value) {
  if (value === null || value === undefined || value === '') {
    return '—';
  }
  return normalizeJavadocTags(String(value))
    .replace(/\n/g, ' ')
    // Wrap bare URLs in inline code so GFM does not autolink them (an adjacent escaped brace
    // would otherwise be swallowed into the URL and fail MDX's URL parsing).
    .replace(/(https?:\/\/[^\s)]+)/g, '`$1`')
    .replace(/\|/g, '\\|')
    .replace(/\{/g, '&#123;')
    .replace(/\}/g, '&#125;')
    .replace(/</g, '&lt;');
}

function frontmatter({id, title, description, audience, sidebarPosition}) {
  const lines = [
    '---',
    `id: ${id}`,
    `title: ${title}`,
    `description: ${description}`,
    'kind: doc',
    'diataxis: reference',
    `audience: ${audience}`,
    `sidebar_position: ${sidebarPosition}`,
    '---',
    '',
    '{/* Generated by scripts/generate-references.mjs — do not edit by hand. */}',
    '',
  ];
  return lines.join('\n');
}

function write(relPath, content) {
  const target = join(REFERENCE_DIR, relPath);
  mkdirSync(dirname(target), {recursive: true});
  writeFileSync(target, content.endsWith('\n') ? content : `${content}\n`, 'utf8');
}

// --- Providers -------------------------------------------------------------------------------

/**
 * Build the provider-matrix table rows and header, one column per emitted model tier — so a
 * legitimate new tier (e.g. a future PREMIUM) appears in the docs without a generator edit. Pure
 * (no file I/O), so it is directly unit-testable.
 *
 * @param {Array<{name: string, requiresApiKey: boolean, tiers?: Record<string, string>}>} providers
 * @param {string[]} tiers the emitted `contracts.modelTiers`, in declaration order
 * @returns {{header: string, separator: string, rows: string[]}}
 */
export function buildProviderTable(providers, tiers) {
  const header = `| Provider | API key required | ${tiers.join(' | ')} |`;
  const separator = `|---|---|${tiers.map(() => '---').join('|')}|`;
  const rows = providers.map((p) => {
    const t = p.tiers || {};
    const tierCells = tiers.map((tier) => cell(t[tier])).join(' | ');
    return `| \`${cell(p.name)}\` | ${p.requiresApiKey ? 'Yes' : 'No'} | ${tierCells} |`;
  });
  return {header, separator, rows};
}

function generateProviders(providers, tiers) {
  const {header, separator, rows} = buildProviderTable(providers, tiers);
  const body = [
    frontmatter({
      id: 'reference-providers',
      title: 'Provider support',
      description: 'The supported LLM providers, whether each requires an API key, and the shipped per-tier model defaults.',
      audience: 'integrating',
      sidebarPosition: 1,
    }),
    '# Provider support',
    '',
    'Generated from the provider service-provider registrations and the shipped model-tier defaults.',
    'The deterministic test-only `fake` provider is intentionally excluded.',
    '',
    header,
    separator,
    ...rows,
    '',
  ].join('\n');
  write(join('providers', 'index.mdx'), body);
}

// --- Contract tables -------------------------------------------------------------------------

function generateSealedTable({file, id, title, description, audience, heading, intro, entries}) {
  const rows = entries.map((e) => `| \`${cell(e.jsonType)}\` | \`${cell(e.javaName)}\` |`);
  const body = [
    frontmatter({id, title, description, audience, sidebarPosition: 1}),
    `# ${heading}`,
    '',
    intro,
    '',
    '| JSON `type` | Java type |',
    '|---|---|',
    ...rows,
    '',
  ].join('\n');
  write(file, body);
}

function generateEnumList({file, id, title, description, audience, heading, intro, names}) {
  const rows = names.map((n) => `| \`${cell(n)}\` |`);
  const body = [
    frontmatter({id, title, description, audience, sidebarPosition: 1}),
    `# ${heading}`,
    '',
    intro,
    '',
    '| Value |',
    '|---|',
    ...rows,
    '',
  ].join('\n');
  write(file, body);
}

// --- Config: bootstrap, env/sysprop -----------------------------------------------------------

function generateBootstrapConfig(methods) {
  const rows = methods.map((m) => `| \`${cell(m.method)}\` | \`${cell(m.paramType)}\` |`);
  const body = [
    frontmatter({
      id: 'reference-config-bootstrap',
      title: 'Bootstrap builder configuration',
      description: 'The value-configuration methods on the framework-agnostic AgentForge4jBootstrap.Builder.',
      audience: 'integrating',
      sidebarPosition: 2,
    }),
    '# Bootstrap builder configuration',
    '',
    'The framework-agnostic `AgentForge4jBootstrap.Builder` value-configuration methods (the data-valued',
    'settings). SPI/extension-wiring setters are intentionally not listed here. Generated from the live',
    'builder; parameter types only (method descriptions are not retained in compiled bytecode).',
    '',
    '| Method | Parameter type |',
    '|---|---|',
    ...rows,
    '',
  ].join('\n');
  write(join('config', 'bootstrap.mdx'), body);
}

function generateEnvSysprop(fixture) {
  const keyRows = fixture.keys.map((k) =>
    `| \`${cell(k.key)}\` | ${k.envReachable ? `\`${cell(k.envVar)}\`` : '— (system property only)'} | \`${cell(k.type)}\` | ${cell(k.description)} |`,
  );
  const prefixRows = fixture.prefixes.map((p) =>
    `| \`${cell(p.prefix)}\` | ${p.envReachable ? 'partly' : '— (system property only)'} | ${cell(p.description)} |`,
  );
  const body = [
    frontmatter({
      id: 'reference-config-env-sysprop',
      title: 'Environment & system-property configuration',
      description: 'The environment-variable and system-property configuration keys the framework-agnostic bootstrap recognises.',
      audience: 'integrating',
      sidebarPosition: 3,
    }),
    '# Environment & system-property configuration',
    '',
    'The framework-agnostic bootstrap reads `agentforge4j.*` system properties and `AGENTFORGE4J_*`',
    'environment variables. Environment names have their prefix stripped and `_` replaced with `.`,',
    'lowercased — so an environment variable can only produce a dot-separated lowercase key and **cannot',
    'produce a hyphen**; hyphenated keys are therefore system-property only. System properties win over',
    'environment variables on collision.',
    '',
    '## Keys',
    '',
    '| System property | Environment variable | Type | Description |',
    '|---|---|---|---|',
    ...keyRows,
    '',
    '## Prefixed keys',
    '',
    '| Prefix | Environment-reachable | Description |',
    '|---|---|---|',
    ...prefixRows,
    '',
  ].join('\n');
  write(join('config', 'env-sysprop.mdx'), body);
}

function generateSpringConfig(metadata) {
  const properties = (metadata.properties || [])
    .slice()
    .sort((a, b) => a.name.localeCompare(b.name));
  const rows = properties.map((p) => {
    const type = (p.type || '').replace(/^java\.lang\./, '').replace(/^java\.util\./, '');
    return `| \`${cell(p.name)}\` | \`${cell(type)}\` | ${cell(p.description)} |`;
  });
  const body = [
    frontmatter({
      id: 'reference-config-spring',
      title: 'Spring Boot configuration',
      description: 'The Spring Boot starter configuration properties under the agentforge4j prefix.',
      audience: 'integrating',
      sidebarPosition: 1,
    }),
    '# Spring Boot configuration',
    '',
    'The Spring Boot starter configuration properties, generated from the Spring configuration metadata',
    `the configuration processor emits at build time (${properties.length} properties).`,
    '',
    '| Property | Type | Description |',
    '|---|---|---|',
    ...rows,
    '',
  ].join('\n');
  write(join('config', 'spring.mdx'), body);
}

function generateConfigIndex() {
  const body = [
    frontmatter({
      id: 'reference-config',
      title: 'Configuration',
      description: 'Reference for every AgentForge4j configuration surface.',
      audience: 'integrating',
      sidebarPosition: 0,
    }),
    '# Configuration reference',
    '',
    'AgentForge4j has three configuration surfaces, each documented from source:',
    '',
    '- [Spring Boot configuration](./spring.mdx) — the Spring Boot starter properties.',
    '- [Bootstrap builder configuration](./bootstrap.mdx) — the framework-agnostic builder settings.',
    '- [Environment & system properties](./env-sysprop.mdx) — `AGENTFORGE4J_*` / `agentforge4j.*` keys.',
    '',
  ].join('\n');
  write(join('config', 'index.mdx'), body);
}

// --- Schemas ---------------------------------------------------------------------------------

// A `$ref` can point at: a `$defs` entry in the SAME schema file ("#/$defs/Foo"); a `$defs` entry in
// ANOTHER schema file ("other.schema.json#/$defs/Foo" — e.g. blueprint.schema.json's Executable
// referencing workflow.schema.json's StepDefinition); or a whole OTHER document, with no fragment at
// all ("other.schema.json", or the bare self-reference "#" for the current document). Only the
// same-file-$defs case is a same-page anchor; the other two must link to a different page (or that
// page's own root), never `#<name>` on the CURRENT page — a same-page anchor that does not exist
// there is exactly the "broken anchor" class of defect this generator must never produce silently.

/** The `$defs` member name from a ref fragment, e.g. "#/$defs/Foo" -> "Foo". `null` for a whole-
 * document reference with no `$defs` fragment (e.g. "#" or "other.schema.json"). */
function refDefName(ref) {
  const match = /#\/\$defs\/(.+)$/.exec(ref || '');
  return match ? match[1] : null;
}

/** The target schema's file base name from a ref, e.g. "workflow.schema.json#/..." -> "workflow".
 * `null` when the ref has no file prefix (same file as the caller, e.g. "#/$defs/Foo" or "#"). */
function refFile(ref) {
  const match = /^([\w-]+)\.schema\.json/.exec(ref || '');
  return match ? match[1] : null;
}

function typeOf(node, currentSchemaName) {
  if (!node || typeof node !== 'object') {
    return '—';
  }
  if (node.const !== undefined) {
    return `const \`${node.const}\``;
  }
  if (node.$ref) {
    const file = refFile(node.$ref);
    const defName = refDefName(node.$ref);
    if (defName === null) {
      // A whole-document reference ("#" or "other.schema.json") — link to that schema's own page
      // root, never a same-page anchor (nothing named "#" or the bare filename exists on any page).
      const targetFile = file || currentSchemaName;
      if (!targetFile) {
        return `\`${node.$ref}\``; // no page context to link into — inert text, not a dead link
      }
      const label = targetFile.charAt(0).toUpperCase() + targetFile.slice(1);
      return `[${label}](./${targetFile}.mdx)`;
    }
    return file && file !== currentSchemaName
      ? `[${defName}](./${file}.mdx#${defName.toLowerCase()})`
      : `[${defName}](#${defName.toLowerCase()})`;
  }
  if (node.enum) {
    return `enum (${node.enum.map((v) => `\`${v}\``).join(', ')})`;
  }
  if (node.type === 'array') {
    const items = node.items || {};
    return `array of ${typeOf(items, currentSchemaName)}`;
  }
  if (Array.isArray(node.type)) {
    return node.type.join(' \\| ');
  }
  if (node.type) {
    return node.format ? `${node.type} (${node.format})` : node.type;
  }
  if (node.oneOf || node.anyOf) {
    const branches = (node.oneOf || node.anyOf).map((b) => typeOf(b, currentSchemaName));
    return branches.join(' \\| ');
  }
  return 'object';
}

/**
 * Render a `$defs` entry (or the schema root) as whichever shape it actually is: an object with
 * `properties`, a `oneOf`/`anyOf` union of alternatives, an `enum` of literal values, a single
 * `const`, or (falling through) some other scalar `type`. Only a genuinely property-less object
 * schema renders "No properties." — every other real JSON Schema shape gets its own table/line,
 * so a union or enum definition is never silently misreported as empty.
 */
export function propertiesTable(schemaNode, currentSchemaName) {
  const props = schemaNode.properties || {};
  const required = new Set(schemaNode.required || []);
  const names = Object.keys(props);
  if (names.length > 0) {
    const rows = names.map((name) => {
      const p = props[name];
      const req = required.has(name) ? 'yes' : 'no';
      return `| \`${cell(name)}\` | ${typeOf(p, currentSchemaName)} | ${req} | ${cell(p.description)} |`;
    });
    return ['| Property | Type | Required | Description |', '|---|---|---|---|', ...rows, ''];
  }
  if (schemaNode.oneOf || schemaNode.anyOf) {
    const kind = schemaNode.oneOf ? 'oneOf' : 'anyOf';
    const branches = schemaNode.oneOf || schemaNode.anyOf;
    const rows = branches.map((b) => `| ${typeOf(b, currentSchemaName)} |`);
    return [`_One of the following (${kind}):_`, '', '| Alternative |', '|---|', ...rows, ''];
  }
  if (schemaNode.enum) {
    const rows = schemaNode.enum.map((v) => `| \`${cell(v)}\` |`);
    return ['_Enum values:_', '', '| Value |', '|---|', ...rows, ''];
  }
  if (schemaNode.const !== undefined) {
    return [`_Constant value:_ \`${cell(schemaNode.const)}\``, ''];
  }
  if (schemaNode.type && schemaNode.type !== 'object') {
    return [`_Scalar type:_ ${typeOf(schemaNode, currentSchemaName)}`, ''];
  }
  return ['_No properties._', ''];
}

// A representative, source-backed, schema-valid fixture per schema (paths relative to the repo root;
// resolved + validated by the include plugin's allowlist). The agent example is the authoritative
// schema fixture (real provider), not an example agent.json (which uses the test-only fake provider).
// Integration has no source-backed fixture, so it renders schema-only.
const WORKED_EXAMPLE = {
  workflow: 'agentforge4j-examples/framework-examples/quick-start/src/main/resources/workflows/quick-start.workflow/workflow.json',
  agent: 'agentforge4j-schema/src/test/resources/fixtures/agent.valid.json',
  artifact: 'agentforge4j-examples/workflow-language-examples/wl-human-in-the-loop/src/main/resources/workflows/wl-human-in-the-loop.workflow/request-form.artifact.json',
  blueprint: 'agentforge4j-examples/workflow-language-examples/wl-loop/src/main/resources/workflows/wl-loop-fixed.workflow/fixed-body.blueprint.json',
};

function generateSchemaPage(name, schema, sidebarPosition) {
  const lines = [
    frontmatter({
      id: `reference-schema-${name}`,
      title: `${schema.title || name} schema`,
      description: `JSON schema reference for the ${name} document type.`,
      audience: 'authoring',
      sidebarPosition,
    }),
    `# ${schema.title || name} schema`,
    '',
    schema.description || `The \`${name}\` document type, validated against the published JSON schema.`,
    '',
  ];
  if (WORKED_EXAMPLE[name]) {
    // A real, schema-valid example, included from source (filled by the include remark plugin).
    lines.push(
      '## Example',
      '',
      `\`\`\`json file=${WORKED_EXAMPLE[name]} title="${name}.json"`,
      '```',
      '',
    );
  }
  lines.push('## Properties', '', ...propertiesTable(schema, name));
  const defs = schema.$defs || {};
  const defNames = Object.keys(defs);
  if (defNames.length > 0) {
    lines.push('## Definitions', '');
    for (const defName of defNames) {
      lines.push(`### ${defName}`, '');
      const def = defs[defName];
      if (def.description) {
        lines.push(def.description, '');
      }
      lines.push(...propertiesTable(def, name));
    }
  }
  write(join('schemas', `${name}.mdx`), lines.join('\n'));
}

function generateSchemasIndex(names) {
  const links = names.map((n) => `- [${n}](./${n}.mdx)`);
  const body = [
    frontmatter({
      id: 'reference-schemas',
      title: 'Schemas',
      description: 'Reference for the AgentForge4j JSON schemas that documents are validated against.',
      audience: 'authoring',
      sidebarPosition: 0,
    }),
    '# Schema reference',
    '',
    'The Draft 2020-12 JSON schemas that AgentForge4j documents are validated against, rendered from',
    'the published schema files:',
    '',
    ...links,
    '',
  ].join('\n');
  write(join('schemas', 'index.mdx'), body);
}

// --- Main ------------------------------------------------------------------------------------

function main() {
  const providers = readJson(join(EMITTER_OUT, 'providers.json'), 'providers.json (emitter output)');
  const contracts = readJson(join(EMITTER_OUT, 'contract-sets.json'), 'contract-sets.json (emitter output)');
  const bootstrap = readJson(join(EMITTER_OUT, 'bootstrap-config.json'), 'bootstrap-config.json (emitter output)');
  const envFixture = readJson(join(here, 'env-sysprop-keys.json'), 'env-sysprop-keys.json (fixture)');
  const springMetadata = readJson(SPRING_METADATA, 'spring-configuration-metadata.json (build output)');

  // Soft drift guard: every env fixture entry's builderMethod must exist in the emitted value-config set.
  const bootstrapMethods = new Set(bootstrap.map((m) => m.method));
  for (const k of envFixture.keys) {
    if (k.builderMethod && !bootstrapMethods.has(k.builderMethod)) {
      console.error(`generate-references: env fixture key '${k.key}' maps to unknown builder method '${k.builderMethod}'.`);
      process.exit(1);
    }
  }

  generateProviders(providers, contracts.modelTiers);

  generateConfigIndex();
  generateSpringConfig(springMetadata);
  generateBootstrapConfig(bootstrap);
  generateEnvSysprop(envFixture);

  generateSealedTable({
    file: 'behaviours.mdx',
    id: 'reference-behaviours',
    title: 'Behaviours',
    description: 'Reference for the AgentForge4j step behaviours.',
    audience: 'authoring',
    heading: 'Behaviours reference',
    intro: 'The step behaviours a workflow can use, generated from the sealed behaviour contract.',
    entries: contracts.stepBehaviours,
  });
  generateSealedTable({
    file: 'commands.mdx',
    id: 'reference-commands',
    title: 'Commands',
    description: 'Reference for the commands an AgentForge4j LLM step can emit.',
    audience: 'authoring',
    heading: 'Commands reference',
    intro: 'The commands an LLM step can emit, generated from the sealed command contract.',
    entries: contracts.llmCommands,
  });
  generateEnumList({
    file: 'events.mdx',
    id: 'reference-events',
    title: 'Events',
    description: 'Reference for the events an AgentForge4j run emits.',
    audience: 'authoring',
    heading: 'Events reference',
    intro: 'The event types a run emits, generated from the workflow-event contract.',
    names: contracts.workflowEventTypes,
  });
  generateEnumList({
    file: 'statuses.mdx',
    id: 'reference-statuses',
    title: 'Statuses',
    description: 'Reference for the AgentForge4j workflow run statuses.',
    audience: 'authoring',
    heading: 'Statuses reference',
    intro: 'The run statuses, generated from the workflow-status contract.',
    names: contracts.workflowStatuses,
  });

  const schemaNames = ['workflow', 'agent', 'blueprint', 'artifact', 'integration'];
  schemaNames.forEach((name, index) => {
    const schema = readJson(join(SCHEMA_DIR, `${name}.schema.json`), `${name}.schema.json`);
    generateSchemaPage(name, schema, index + 1);
  });
  generateSchemasIndex(schemaNames);

  console.log('generate-references: wrote provider matrix, config (spring/bootstrap/env), schemas, and contract tables.');
}

// CLI entry. Guarded so pure exports (e.g. buildProviderTable) can be unit-tested without
// requiring the emitter output / OSS build main() depends on.
if (process.argv[1]?.endsWith('generate-references.mjs')) {
  main();
}
